UPDATE ai_settings SET prompt = 'Сгенерируй одно уникальное, забавное имя для славянского кибернетического духа-Бабая. Пол: {gender}. Стиль: {style}. Имя должно состоять из одного или двух слов. Верни ТОЛЬКО само имя, без нумерации, без пояснений, без кавычек.' WHERE section_id = 'names'; UPDATE ai_settings SET prompt = 'Нарисуй портрет славянского кибернетического духа по имени {name} ({gender}) в пижаме. Особые приметы: {wishes}. Стиль: {style}. Персонаж страшный и смешной одновременно, с длинным языком больше метра. Высокое качество, детализированный, атмосферный.' WHERE section_id = 'avatar';